interface ListeningIndicatorProps {
  isListening: boolean;
}

export function ListeningIndicator({ isListening }: ListeningIndicatorProps) {
  if (!isListening) return <div className="h-8" />; // Placeholder to prevent layout shift

  return (
    <div className="flex flex-col items-center gap-3 h-8 animate-in fade-in duration-300">
      <div className="flex items-center gap-1.5">
        {[...Array(5)].map((_, i) => (
          <div 
            key={i}
            className="w-1.5 bg-red-400 rounded-full animate-wave"
            style={{ 
              height: '16px',
              animationDelay: `${i * 0.15}s`
            }}
          />
        ))}
      </div>
      <span className="text-xs font-medium text-red-400 uppercase tracking-widest">Listening</span>
    </div>
  );
}
